import{a as e,i as t,r as n,t as r}from"./app-CnBAqX6l.js";var i=JSON.parse(`{"path":"/%E6%96%B0%E8%B4%A8%E7%94%9F%E4%BA%A7%E5%8A%9B%E8%AF%A6%E8%A7%A3.html","title":"新质生产力详解","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1774836273000,"contributors":[{"name":"JiraiyaChen","username":"JiraiyaChen","email":"979526234@qq.com","commits":1,"url":"https://github.com/JiraiyaChen"}],"changelog":[{"hash":"7318efb2b3433787199988c8a1b814510fda6eb4","time":1774836273000,"email":"979526234@qq.com","author":"JiraiyaChen","message":"Add politics/时政 docs"}]},"filePathRelative":"新质生产力详解.md"}`),a={name:`新质生产力详解.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="新质生产力详解" tabindex="-1"><a class="header-anchor" href="#新质生产力详解"><span>新质生产力详解</span></a></h1><h2 id="基本定义" tabindex="-1"><a class="header-anchor" href="#基本定义"><span>基本定义</span></a></h2><p><strong>新质生产力</strong>是创新起主导作用，摆脱传统经济增长方式、生产力发展路径，具有<strong>高科技、高效能、高质量</strong>特征，符合新发展理念的<strong>先进生产力质态</strong>。</p><p><em>来源：习近平总书记重要讲话（2024年1月31日中央政治局第十一次集体学习）</em></p><hr><h2 id="三大内涵" tabindex="-1"><a class="header-anchor" href="#三大内涵"><span>三大内涵</span></a></h2><h3 id="_1-技术革命性突破" tabindex="-1"><a class="header-anchor" href="#_1-技术革命性突破"><span>1. 技术革命性突破</span></a></h3><ul><li>由新技术突破催生</li><li>如人工智能、量子计算、生物技术等</li></ul><h3 id="_2-生产要素创新性配置" tabindex="-1"><a class="header-anchor" href="#_2-生产要素创新性配置"><span>2. 生产要素创新性配置</span></a></h3><ul><li>数据已成为新的生产要素</li><li>太空育种、深海采矿等开辟新空间</li></ul><h3 id="_3-产业深度转型升级" tabindex="-1"><a class="header-anchor" href="#_3-产业深度转型升级"><span>3. 产业深度转型升级</span></a></h3><ul><li>传统产业改造升级</li><li>战略性新兴产业</li><li>未来产业新赛道</li></ul><hr><h2 id="核心标志" tabindex="-1"><a class="header-anchor" href="#核心标志"><span>核心标志</span></a></h2><ul><li><strong>全要素生产率大幅提升</strong></li><li>劳动者、劳动资料、劳动对象及其优化组合的<strong>跃升</strong></li></ul><hr><h2 id="发展要求-因地制宜" tabindex="-1"><a class="header-anchor" href="#发展要求-因地制宜"><span>发展要求：因地制宜</span></a></h2><p>习近平总书记强调要**&quot;因地制宜&quot;**发展新质生产力：</p><ol><li><strong>要防止一哄而上、泡沫化</strong></li><li><strong>不要搞一种模式</strong></li><li><strong>避免同质化竞争</strong></li></ol><hr><h2 id="战略意义" tabindex="-1"><a class="header-anchor" href="#战略意义"><span>战略意义</span></a></h2><ul><li>发展新质生产力是<strong>推动高质量发展的内在要求和重要着力点</strong></li><li>是引领高质量发展、推进中国式现代化的<strong>关键动力</strong></li></ul><hr><h2 id="发展历程" tabindex="-1"><a class="header-anchor" href="#发展历程"><span>发展历程</span></a></h2><table><thead><tr><th>时间</th><th>事件</th></tr></thead><tbody><tr><td>2023年7月</td><td>习近平总书记在四川等地考察时首次提出&quot;新质生产力&quot;</td></tr><tr><td>2024年1月</td><td>中央政治局第十一次集体学习，系统阐释新质生产力</td></tr><tr><td>2024年3月</td><td>参加江苏代表团审议，强调&quot;因地制宜发展新质生产力&quot;</td></tr><tr><td>2025年</td><td>继续强调发展新质生产力是&quot;必答题&quot;</td></tr><tr><td>2025年11月</td><td>《求是》杂志发表习近平总书记重要文章《因地制宜发展新质生产力》</td></tr></tbody></table><hr><p><em>整理：贾布斯</em><em>日期：2026年3月27日</em></p>`,27)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};